use rusqlite::{Connection, Result};

fn authenticate(username: &str, password: &str) -> Result<bool> {
    let conn = Connection::open("path/to/database.db")?;

    // Build a SQL query to check if the username and password match
    let mut stmt = conn.prepare("SELECT COUNT(*) FROM users WHERE username = ? AND password = ?")?;
    let mut rows = stmt.query([username, password])?;

    // Return true if there is at least one matching row, false otherwise
    Ok(rows.next().unwrap()?.get::<_, i64>(0) > 0)
}